svg.script:

(function() {
  var phrases = [
    "Finalizando DAM, buscando prácticas",
    "Java, SQL, Android, Spring Boot",
    "Mejorando en WEB",
    "Python en progreso",
    "Quiero crecer en equipo real",
    "Adaptable y con ganas de aprender",
    "Disponible para prácticas"
  ];
  var typeSpeed = 70;
  var pauseBetween = 1800;
  var eraseSpeed = 35;
  var textEl = document.getElementById('text');
  var cursorEl = document.getElementById('cursor');
  var phraseIndex = 0;
  var charIndex = 0;
  var isDeleting = false;
  var currentText = '';

  function typeEffect() {
    var fullPhrase = phrases[phraseIndex];

    if (!isDeleting) {
      currentText = fullPhrase.substring(0, charIndex + 1);
      charIndex++;

      if (charIndex === fullPhrase.length) {
        isDeleting = true;
        setTimeout(typeEffect, pauseBetween);
        return;
      }
    } else {
      currentText = fullPhrase.substring(0, charIndex - 1);
      charIndex--;

      if (charIndex === 0) {
        isDeleting = false;
        phraseIndex = (phraseIndex + 1) % phrases.length;
        setTimeout(typeEffect, typeSpeed);
        return;
      }
    }

    textEl.textContent = currentText;

    var metrics = textEl.getComputedTextLength();
    cursorEl.setAttribute('x', 12 + metrics);
    cursorEl.setAttribute('y', 14);

    var delay = isDeleting ? eraseSpeed : typeSpeed;
    setTimeout(typeEffect, delay);
  }

  setTimeout(typeEffect, 300);
})();
